114	export const runScenario = (scenario: any): unknown => {
115	  const yearsWithMHPCO = scenario.customer?.yearsWithMHPCO ?? 0;
116	  let quoteIndex = 0;
117	  const policies: Record<number, Policy> = {};
118	  const results = scenario.steps.map((step: any, stepIndex: number) => {
119	    if (step.op === "claim") {
120	      return handleClaim(step, policies);
121	    }
122	    for (const item of step.items) {
123	      if (!(item.type in BASE_PREMIUMS)) {
124	        throw new Error(`unknown item type: ${item.type}`);
125	      }
126	    }
127	    const premium = quotePremium(step.items, yearsWithMHPCO, quoteIndex);
128	    const insuranceSum = insuranceSumFor(step.items);
129	    policies[stepIndex] = {
130	      items: step.items,
131	      insuranceSum,
132	      remainingCap: insuranceSum * CAP_MULTIPLIER,
133	    };
134	    quoteIndex++;
135	    return { premium };
136	  });
137	  return { results };
138	};
